module alu_8bit (
    input [7:0] obf_a,
    input [7:0] b,
    input [2:0] control,
    output reg [7:0] out
);

    always @(*) begin
        case (control)
            3'b000: out = obf_a + b;
            3'b001: out = obf_a - b;
            3'b010: out = obf_a & b;
            3'b011: out = obf_a | b;
            3'b100: out = obf_a ^ b;
            default: out = 8'b00000000;
        endcase
    end

endmodule
